| `navigator` | `userAgent` | string | `"Mozilla/5.0 ..."` |
| `navigator` | `platform` | string | `"Win32"` |
| `navigator` | `language` | string | `"en-US"` |
| `navigator` | `onLine` | boolean | `true` |
| `screen` | `width` | number | `1920` |
